+    let ext = if format == "pdf" { "html" } else { "html" };
+    let filename = format!("chronicle_{job_id}.{ext}");
+    let dir = PathBuf::from(output_dir);
+    fs::create_dir_all(&dir)
+        .map_err(|e| format!("nepodařilo se vytvořit výstupní adresář: {e}"))?;
