+    fs::write(&dest, &html)
+        .map_err(|e| format!("nepodařilo se zapsat kroniku: {e}"))?;
+
+    Ok(dest.to_string_lossy().to_string())
+}
+
+fn theme_colors(theme: &str) -> (&'static str, &'static str, &'static str, &'static str) {
+    match theme {
+        "horror" => (
+            "#0a0a0a",
+            "#8b0000",
+            "#c0c0c0",
+            "'Courier New', monospace",
+        ),
+        "cyberpunk" => (
+            "#0d0221",
+            "#00ffff",
+            "#c0c0ff",
+            "'Consolas', monospace",
+        ),
+        "universal" => (
+            "#ffffff",
+            "#333333",
+            "#000000",
+            "'Georgia', serif",
+        ),
+        _ => (
+            // fantasy (default)
+            "#f5e6c8",
+            "#8b6914",
+            "#3d2b1f",
+            "'Georgia', serif",
+        ),
